import type { LogEntry, LogLevel, LogsResponse } from '@motivation/shared';
import stylesText from './log-viewer.css?inline';
import { cssStyleSheet } from '../../utils/css.js';

const styles = cssStyleSheet(stylesText);

export interface LogsSourceFilters {
    level?: LogLevel[];
    search?: string;
}

export type LogsSource = (filters: LogsSourceFilters) => Promise<LogsResponse>;

const ALL_LEVELS = ['debug', 'info', 'warn', 'error'] as const satisfies readonly LogLevel[];

const template = document.createElement('template');
template.innerHTML = `
<div class="filter-bar">
    <div class="level-toggles" id="level-toggles"></div>
    <input class="search-input" id="search" type="text" placeholder="Search logs...">
</div>
<div class="state" id="loading">Loading logs...</div>
<div class="state" id="error" hidden></div>
<div class="state" id="empty" hidden>No log entries found.</div>
<p class="total-count" id="total" hidden></p>
<ul class="log-list" id="entries" hidden></ul>
<template id="entry-template">
    <li>
        <details class="log-entry">
            <summary class="entry-summary">
                <div class="entry-header">
                    <span class="entry-time"></span>
                    <span class="entry-level"></span>
                    <span class="entry-module"></span>
                    <span class="entry-indicator" aria-label="expand for more" hidden>▸</span>
                </div>
                <div class="entry-message"></div>
            </summary>
            <div class="entry-body">
                <pre class="entry-context"></pre>
            </div>
        </details>
    </li>
</template>
`;

export class LogViewer extends HTMLElement {
    private shadowRootRef: ShadowRoot;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private emptyEl!: HTMLElement;
    private totalEl!: HTMLElement;
    private entriesEl!: HTMLElement;
    private entryTemplateEl!: HTMLTemplateElement;
    private searchInputEl!: HTMLInputElement;
    private levelTogglesEl!: HTMLElement;
    private loadSequence = 0;
    private activeLevels = new Set<LogLevel>(['info', 'warn', 'error']);
    private searchText = '';
    private debounceTimer: ReturnType<typeof setTimeout> | null = null;
    private _source: LogsSource | null = null;
    private _availableLevels: LogLevel[] = ['info', 'warn', 'error'];

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
    }

    set source(fn: LogsSource | null) {
        this._source = fn;
        if (this.isConnected && this.loadingEl) void this.loadData();
    }

    get source(): LogsSource | null {
        return this._source;
    }

    /**
     * Which level toggles to render. Defaults to info/warn/error.
     * Accepts any subset of ALL_LEVELS; order is preserved.
     */
    set availableLevels(levels: LogLevel[]) {
        this._availableLevels = levels.filter((l) => ALL_LEVELS.includes(l));
        if (this.isConnected && this.levelTogglesEl) this.renderLevelToggles();
    }

    get availableLevels(): LogLevel[] {
        return [...this._availableLevels];
    }

    /** Force a reload. Useful for pages that need manual refresh. */
    refresh(): void {
        void this.loadData();
    }

    connectedCallback(): void {
        this.loadingEl = this.shadowRootRef.getElementById('loading') as HTMLElement;
        this.errorEl = this.shadowRootRef.getElementById('error') as HTMLElement;
        this.emptyEl = this.shadowRootRef.getElementById('empty') as HTMLElement;
        this.totalEl = this.shadowRootRef.getElementById('total') as HTMLElement;
        this.entriesEl = this.shadowRootRef.getElementById('entries') as HTMLElement;
        this.entryTemplateEl = this.shadowRootRef.getElementById('entry-template') as HTMLTemplateElement;
        this.searchInputEl = this.shadowRootRef.getElementById('search') as HTMLInputElement;
        this.levelTogglesEl = this.shadowRootRef.getElementById('level-toggles') as HTMLElement;

        this.renderLevelToggles();
        this.shadowRootRef.addEventListener('click', this.handleToggleClick);
        this.searchInputEl.addEventListener('input', this.handleSearchInput);

        void this.loadData();
    }

    disconnectedCallback(): void {
        this.shadowRootRef.removeEventListener('click', this.handleToggleClick);
        this.searchInputEl?.removeEventListener('input', this.handleSearchInput);
        if (this.debounceTimer) clearTimeout(this.debounceTimer);
    }

    private renderLevelToggles(): void {
        this.levelTogglesEl.replaceChildren(
            ...this._availableLevels.map((level) => {
                const btn = document.createElement('button');
                btn.className = 'level-toggle';
                btn.dataset.level = level;
                btn.setAttribute('aria-pressed', this.activeLevels.has(level) ? 'true' : 'false');
                btn.textContent = level;
                return btn;
            }),
        );
    }

    private handleToggleClick = (e: Event) => {
        const target = e.target as HTMLElement;
        const btn = target.closest('.level-toggle') as HTMLButtonElement | null;
        if (!btn) return;

        const level = btn.dataset.level as LogLevel;
        const pressed = btn.getAttribute('aria-pressed') === 'true';

        if (pressed) {
            this.activeLevels.delete(level);
            btn.setAttribute('aria-pressed', 'false');
        } else {
            this.activeLevels.add(level);
            btn.setAttribute('aria-pressed', 'true');
        }

        void this.loadData();
    };

    private handleSearchInput = () => {
        if (this.debounceTimer) clearTimeout(this.debounceTimer);
        this.debounceTimer = setTimeout(() => {
            this.searchText = this.searchInputEl.value;
            void this.loadData();
        }, 300);
    };

    private async loadData(): Promise<void> {
        if (!this.loadingEl) return;

        const source = this._source;
        if (!source) {
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            this.errorEl.textContent = 'No log source configured.';
            return;
        }

        const currentLoad = ++this.loadSequence;
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.emptyEl.hidden = true;
        this.totalEl.hidden = true;
        this.entriesEl.hidden = true;

        try {
            const response = await source({
                level: this.activeLevels.size > 0 ? [...this.activeLevels] : undefined,
                search: this.searchText || undefined,
            });
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;

            if (response.entries.length === 0) {
                this.loadingEl.hidden = true;
                this.emptyEl.hidden = false;
                return;
            }

            this.renderEntries(response.entries, response.total);
        } catch (error) {
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            const message = error instanceof Error ? (error.stack ?? error.message) : String(error);
            this.errorEl.textContent = `Failed to load logs: ${message}`;
        }
    }

    private renderEntries(entries: LogEntry[], total: number): void {
        this.entriesEl.replaceChildren(...entries.map((entry) => {
            const fragment = this.entryTemplateEl.content.cloneNode(true) as DocumentFragment;

            const timeEl = fragment.querySelector('.entry-time') as HTMLElement;
            timeEl.textContent = entry.timestamp.slice(11, 19);

            const levelEl = fragment.querySelector('.entry-level') as HTMLElement;
            levelEl.textContent = entry.level;
            levelEl.classList.add(`entry-level--${entry.level}`);

            (fragment.querySelector('.entry-module') as HTMLElement).textContent = entry.module;
            (fragment.querySelector('.entry-message') as HTMLElement).textContent = entry.message;

            const hasContext = !!entry.context && Object.keys(entry.context).length > 0;
            const indicatorEl = fragment.querySelector('.entry-indicator') as HTMLElement;
            indicatorEl.hidden = !hasContext;

            const contextEl = fragment.querySelector('.entry-context') as HTMLElement;
            contextEl.textContent = hasContext
                ? JSON.stringify(entry.context, null, 2)
                : 'No additional context.';

            return fragment;
        }));

        this.totalEl.textContent = `${total} entr${total === 1 ? 'y' : 'ies'}`;
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.emptyEl.hidden = true;
        this.totalEl.hidden = false;
        this.entriesEl.hidden = false;
    }
}

if (!customElements.get('log-viewer')) {
    customElements.define('log-viewer', LogViewer);
}
